INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1, "春咲 ひより", "お！\nあそこに困ってそうな人発見！", 1, 0, 0, 1001, 0, 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "みんなみたいに\nわたしも強くならなきゃ", 1, "草野 優衣", "大切な人を\n守れるようになりたい…って", 1, 0, 0, 1002, 0, 0, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "フェンシングを始めてみては？", 1, "士条 怜", "キミに必要な集中力と感性が", 1, 0, 0, 1003, 0, 0, "少しは磨かれると思いますよ。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "ねぇ、にいちゃん！", 1, "穂高 みそぎ", "今日はなにして遊ぶ？", 1, 0, 0, 1004, 0, 0, "みそぎはねぇ、\nかくれんぼやりたい！", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "風宮あかりです", 1, "風宮 あかり", "ねぇ…", 1, 0, 0, 1006, 0, 0, "私といっしょに…\nいかない？", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "出雲宮子なのー", 1, "出雲 宮子", "プリンたべたいのー", 1, 0, 0, 1007, 0, 0, "食べ物の恨みは怖いのー", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "ボクは虹村雪。", 1, "虹村 雪", "キミもボクの美貌に\n吸い寄せられたんだね。", 1, 0, 0, 1008, 0, 0, "いいよ。\n見られることは運命さ…", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "フッ…聞いて後悔するがいい！", 1, "柊杏奈", "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1, 0, 0, 1009, 0, 0, "人呼んで「疾風の冥姫」!!", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "マホマホ王国のプリンセス、\nまほ姫どす", 1, "姫宮 真歩", "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1, 0, 0, 1010, 0, 0, "ほんまおおきにやわ～♪", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "衣之咲璃乃です！", 1, "衣之咲 璃乃", "生き別れたお兄ちゃんを探して\n三千世界！", 1, 0, 0, 1011, 0, 0, "ここで会ったが\n100年目～！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1, "柏崎 初音", "ち、超能力って…\n何のことかな～？", 1, 0, 0, 1012, 0, 0, "…って、お願い！\n誰にも言わないでおいて～！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "ちょす！\n美波鈴奈だよ～♪", 1, "美波 鈴奈", "一応カリスマ読モJKやってまっす！", 1, 0, 0, 1016, 0, 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "はいたーい。\n喜屋武香織さー。", 1, "喜屋武 香織", "東京は遊園地みたいなところさー", 1, 0, 0, 1017, 0, 0, "でも、沖縄もとってもいいとこさー", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "支倉伊緒です。", 1, "支倉 伊緒", "先生って呼ばれるのは\nくすぐったいから", 1, 0, 0, 1018, 0, 0, "イオちゃんって呼んでね。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1, "茜 ミミ", "あ！/\お兄ちゃ～ん\nまってよ～", 1, 0, 0, 1020, 0, 0, "ミミをおいてかないでぇ～", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "あ…あの…えっと…\n栗…林…くるみ…です……", 1, "栗林 くるみ", "あの……\nふぇ……", 1, 0, 0, 1021, 0, 0, "ふぇぇぇぇぇん……", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "風宮よりです。\nあああああ！", 1, "風宮 より", "こんな私に貴重な時間を\n割いていただき、", 1, 0, 0, 1022, 0, 0, "なんてありがとうございます！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1, "北条 綾音", "おにいちゃんどこいくの？\nえ？", 1, 0, 0, 1023, 0, 0, "私こっち行きたいー\nね、早く早くー", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "わっ…わっ…私、\n天野すずめといいます！", 1, "天野 すずめ", "ふ、不束者ですが\nどうぞ末永く…って、", 1, 0, 0, 1025, 0, 0, "これて何か違う…\nあああすみません！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "……クスクス…私は\n…倉石恵理子……", 1, "倉石 恵理子", "あなたは…運命の……\n伴侶……", 1, 0, 0, 1027, 0, 0, "離しませんわ………\n絶対に…!!", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1, "佐々木 咲恋", "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1, 0, 0, 1028, 0, 0, "…そうでしょ？？", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "桜井望だよ！\nよろしくねっ", 1, "桜井 望", "ぇっと…\nキミ、私のこと知らないの?!", 1, 0, 0, 1029, 0, 0, "あはは、\n私もまだまだだなぁ～", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "デケデケデンっ！", 1, "ニノン・ジュベール", "初めまして、\n私はニノン・ジュベール申すデス！", 1, 0, 0, 1030, 0, 0, "ショーグン、\nワタシと一緒に天下統一デース！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "上喜しのぶです。\n手元のドクロが父です。", 1, "上喜 しのぶ", "でもって私の隣にいるのが……\nえ、見えない？", 1, 0, 0, 1031, 0, 0, "おかしいですね……", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "目指すはビッグな\nお笑い芸人だっぺ！", 1, "野戸まひる", "けんども\nそれには足りないモンが…", 1, 0, 0, 1033, 0, 0, "そう、\nオラのボケに突っ込める相方が…！", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1, "綾瀬 ゆかり", "ちょっと緊張しちゃって…", 1, 0, 0, 1034, 0, 0, "ちょ\nちょっと一杯飲んできます…！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "氷川鏡華…です", 1, "氷川 鏡華", "知らない人とは話しちゃいけないので", 1, 0, 0, 1036, 0, 0, "これ以上お話しすることは…\nないです！", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "柏崎…栞です。", 1, "柏崎 栞", "……あ、アラーム。", 1, 0, 0, 1038, 0, 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "ふ、双葉碧です。", 1, "双葉 碧", "私、一人も友達がいなくて……", 1, 0, 0, 1040, 0, 0, "野に咲く花が、\n唯一の話相手です。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "三角千歌です。", 1, "三角 千歌", "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1, 0, 0, 1042, 0, 0, "そう思っています。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "安芸真琴だ。", 1, "安芸 真琴", "あぁ？\nお前のそいつの仲間か？", 1, 0, 0, 1043, 0, 0, "う、疑ってすまなかったな…", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "わらわこそは夜を総べる者！", 1, "イリヤ・オーンスタイン", "生けとし生ける全ての者よ！", 1, 0, 0, 1044, 0, 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "そこで騎士は妖精を乱暴に……", 1, "遠見 空花", "ぐふふふふ……はっ！", 1, 0, 0, 1045, 0, 0, "ｌク、クウカに何かご用ですか!?", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1, "宮坂たまき", "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1, 0, 0, 1046, 0, 0, "う～ん…\n猫ってホントに最高にゃ～♪", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "大神美冬よ！", 1, "大神 美冬", "それでは早速クエストに…", 1, 0, 0, 1048, 0, 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "星野静流だよ！", 1, "星野静流", "クエストもバトルも\n掃除も洗濯も", 1, 0, 0, 1049, 0, 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "アタシは玉泉美咲。", 1, "玉泉美咲", "見ての通りの\nセクシー美少女で", 1, 0, 0, 1050, 0, 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "？？？", 1, "リマ", "？？？？", 1, 0, 0, 1052, 0, 0, "？？？？", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "モニカ・ヴァイスヴィントだ。", 1, "モニカ・ヴァイスヴィント", "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1053, 0, 0, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "モニカ・ヴァイスヴィントだ。", 1, "ペコリーヌ", "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1058, 0, 0, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "モニカ・ヴァイスヴィントだ。", 1, "コッコロ", "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1059, 0, 0, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, "モニカ・ヴァイスヴィントだ。", 1, "キャル", "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1060, 0, 0, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
